ase tracking-wider">{{ $movie->genre }}</span>                    @if($movie->collection_type)                        <span class="w-1 h-1 bg-blue-500 rounded-full opacity-40"></span>                        <span class="text-[10px] text-blue-400 font-black uppercase tracking-widest">{{ $movie->collection_type }}</span>                    @endif                    @if($movie->boxset_children_count > 0)                        <span class="w-1 h-1 bg-indigo-500 rounded-full opacity-40"></span>                        <button @click.stop="$dispatch('open-boxset', { id: {{ $movie->id }}, title: '{{ addslashes($movie->title) }}' })"                                class="text-[10px] text-indigo-400 font-black uppercase tracking-widest hover:text-indigo-300 transition-colors flex items-center gap-1">                            <i class="bi bi-collection-play-fill"></i>                            <span>{{ __('BoxSet (:count)', ['count' => $movie->boxset_children_count]) }}</span>                        </button>                    @endif                </div>            </div>            <!-- Rating -->            <div class="flex flex-col items-end shrink-0">                <div class="flex items-center gap-1.5 bg-white/5 px-2.5 py-1 rounded-xl border border-white/10">                    <i class="bi bi-star-fill text-xs text-yellow-400"></i>                    <span class="text-sm font-black text-white">{{ number_format($movie->rating ?? 0, 1) }}</span>                </div>            </div>        </div>        @if($movie->overview)            <p class="mt-3 text-xs text-gray-500 line-clamp-2 leading-relaxed">                {{ $movie->overview }}            </p>        @endif    </div>    <!-- Action Arrow -->    <div class="shrink-0 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pr-2">        <div class="w-10 h-10 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-400 border border-blue-500/20">            <i class="bi bi-chevron-right text-lg"></i>        </div>    </div></div>